const items = $input.all();
const results = [];
for (const item of items) {
  const data = item.json;
  const postId = data.postId || item.json.post_id;
  const timeline = data.timeline || [];
  for (const point of timeline) {
    results.push({
      json: {
        post_id: postId,
        date: point.date,
        impressions: point.impressions || 0,
        reach: point.reach || 0,
        likes: point.likes || 0,
        comments: point.comments || 0,
        shares: point.shares || 0,
        saves: point.saves || 0,
        clicks: point.clicks || 0,
        views: point.views || 0
      }
    });
  }
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const data = item.json;
  const acc = data.accounts && data.accounts[0];
  if (!acc) continue;
  const accountId = acc._id || acc.accountId;
  const timeline = data.stats && data.stats[accountId] || [];
  results.push({
    json: {
      accountId: accountId,
      currentFollowers: acc.currentFollowers || 0,
      growth: acc.growth || 0,
      growthPercentage: acc.growthPercentage || 0,
      lastUpdated: acc.lastUpdated || new Date().toISOString(),
      timeline: timeline
    }
  });
}
return results;

