=INSERT INTO s_zernio.linkedin_follower_stats_timeline (account_id, date, followers_count)
VALUES (
  '{{ $json.accountId }}',
  '{{ $json.date }}',
  {{ $json.followersCount }}
)
ON CONFLICT (account_id, date)
DO UPDATE SET
  followers_count = EXCLUDED.followers_count;

